import { Test } from "@nestjs/testing";

import { AppConfigService } from "@src/infrastructure/api/config/providers/services/app-config.service";

import { createFindAllOptionsFromQueryDto } from "@shared/application/mappers/find-all-query-dto/find-all-query-dto.mappers";

import { ArchiveQuestionUseCase } from "@question/application/use-cases/archive-question/archive-question.use-case";
import { ModifyQuestionUseCase } from "@question/application/use-cases/modify-question/modify-question.use-case";
import { AssignThemeToQuestionUseCase } from "@question/application/use-cases/question-theme-assignment/assign-theme-to-question/assign-theme-to-question.use-case";
import { RemoveThemeFromQuestionUseCase } from "@question/application/use-cases/question-theme-assignment/remove-theme-from-question/remove-theme-from-question.use-case";
import { ModifyQuestionThemeAssignmentUseCase } from "@question/application/use-cases/question-theme-assignment/modify-question-theme-assignment/modify-question-theme-assignment.use-case";
import { createQuestionCreationCommandFromDto, createQuestionModificationCommandFromDto, createAdminQuestionDtoFromEntity } from "@question/application/mappers/question.mappers";
import { createQuestionThemeAssignmentCreationCommandFromDto, createQuestionThemeAssignmentModificationCommandFromDto } from "@question/application/mappers/question-theme-assignment.mappers";
import { createQuestionFilterOptionsFromQueryDto } from "@question/application/mappers/question-filter-query-dto/question-filter-query-dto.mappers";
import { FindQuestionsUseCase } from "@question/application/use-cases/find-questions/find-questions.use-case";
import { FindQuestionByIdUseCase } from "@question/application/use-cases/find-question-by-id/find-question-by-id.use-case";
import { GetQuestionStatsUseCase } from "@question/application/use-cases/get-question-stats/get-question-stats.use-case";
import { CreateQuestionUseCase } from "@question/application/use-cases/create-question/create-question.use-case";
import { AdminQuestionController } from "@question/infrastructure/http/controllers/admin-question/admin-question.controller";

import { createMockedArchiveQuestionUseCase } from "@mocks/contexts/question/application/use-cases/archive-question.use-case.mock";
import { createMockedModifyQuestionUseCase } from "@mocks/contexts/question/application/use-cases/modify-question.use-case.mock";
import { createMockedAppConfigService } from "@mocks/infrastructure/api/config/providers/services/app-config.service.mock";
import { createMockedFindQuestionsUseCase } from "@mocks/contexts/question/application/use-cases/find-questions.use-case.mock";
import { createMockedFindQuestionByIdUseCase } from "@mocks/contexts/question/application/use-cases/find-question-by-id.use-case.mock";
import { createMockedCreateQuestionUseCase } from "@mocks/contexts/question/application/use-cases/create-question.use-case.mock";
import { createMockedAssignThemeToQuestionUseCase } from "@mocks/contexts/question/application/use-cases/question-theme-assignment/assign-theme-to-question.use-case.mock";
import { createMockedRemoveThemeFromQuestionUseCase } from "@mocks/contexts/question/application/use-cases/question-theme-assignment/remove-theme-from-question.use-case.mock";
import { createMockedModifyQuestionThemeAssignmentUseCase } from "@mocks/contexts/question/application/use-cases/question-theme-assignment/modify-question-theme-assignment.use-case.mock";
import { createMockedGetQuestionStatsUseCase } from "@mocks/contexts/question/application/use-cases/get-question-stats.use-case.mock";

import { createFakeAdminQuestionDto } from "@faketories/contexts/question/dto/admin-question/admin-question.dto.faketory";
import { createFakeQuestion } from "@faketories/contexts/question/entity/question.entity.faketory";
import { createFakeQuestionCreationDto } from "@faketories/contexts/question/dto/question-creation/question-creation.dto.faketory";
import { createFakeQuestionCreationCommand } from "@faketories/contexts/question/commands/question.commands.faketory";
import { createFakeQuestionModificationCommand } from "@faketories/contexts/question/commands/question-modification.commands.faketory";
import { createFakeQuestionModificationDto } from "@faketories/contexts/question/dto/question-modification/question-modification.dto.faketory";
import { createFakeQuestionThemeAssignmentCreationDto } from "@faketories/contexts/question/dto/question-creation/question-theme-assignment-creation/question-theme-assignment-creation.dto.faketory";
import { createFakeQuestionThemeAssignmentCreationCommand } from "@faketories/contexts/question/commands/question-theme-assignment/commands/question-theme-assignment.commands.faketory";
import { createFakeQuestionThemeAssignmentModificationDto } from "@faketories/contexts/question/dto/question-theme-assignment-modification/question-theme-assignment-modification.dto.faketory";
import { createFakeQuestionThemeAssignmentModificationCommand } from "@faketories/contexts/question/commands/question-theme-assignment/commands/question-theme-assignment-modification.commands.faketory";
import { createFakeAdminFindQuestionsQueryDto } from "@faketories/contexts/question/dto/admin-find-questions-query/admin-find-questions-query.dto.faketory";
import { createFakeQuestionStatsDto } from "@faketories/contexts/question/dto/question-stats/question-stats.dto.faketory";

import type { Mock } from "vitest";

import type { FindAllOptions } from "@shared/domain/types/find/find.types";
import type { QuestionFilterOptions, QuestionSortableField } from "@question/domain/types/question.types";

vi.mock(import("@question/application/mappers/question.mappers"));
vi.mock(import("@question/application/mappers/question-theme-assignment.mappers"));
vi.mock(import("@shared/application/mappers/find-all-query-dto/find-all-query-dto.mappers"));

describe("Admin Question Controller", () => {
  let adminQuestionController: AdminQuestionController;
  let mocks: {
    services: {
      appConfig: ReturnType<typeof createMockedAppConfigService>;
    };
    useCases: {
      findQuestions: ReturnType<typeof createMockedFindQuestionsUseCase>;
      findQuestionById: ReturnType<typeof createMockedFindQuestionByIdUseCase>;
      getQuestionStats: ReturnType<typeof createMockedGetQuestionStatsUseCase>;
      createQuestion: ReturnType<typeof createMockedCreateQuestionUseCase>;
      archiveQuestion: ReturnType<typeof createMockedArchiveQuestionUseCase>;
      modifyQuestion: ReturnType<typeof createMockedModifyQuestionUseCase>;
      assignThemeToQuestion: ReturnType<typeof createMockedAssignThemeToQuestionUseCase>;
      removeThemeFromQuestion: ReturnType<typeof createMockedRemoveThemeFromQuestionUseCase>;
      modifyQuestionThemeAssignment: ReturnType<typeof createMockedModifyQuestionThemeAssignmentUseCase>;
    };
    mappers: {
      createAdminQuestionDtoFromEntity: Mock;
      createQuestionCreationCommandFromDto: Mock;
      createQuestionModificationCommandFromDto: Mock;
      createQuestionThemeAssignmentCreationCommandFromDto: Mock;
      createQuestionThemeAssignmentModificationCommandFromDto: Mock;
      createFindAllOptionsFromQueryDto: Mock;
    };
  };

  beforeEach(async() => {
    mocks = {
      services: {
        appConfig: createMockedAppConfigService(),
      },
      useCases: {
        findQuestions: createMockedFindQuestionsUseCase(),
        findQuestionById: createMockedFindQuestionByIdUseCase(),
        getQuestionStats: createMockedGetQuestionStatsUseCase(),
        createQuestion: createMockedCreateQuestionUseCase(),
        archiveQuestion: createMockedArchiveQuestionUseCase(),
        modifyQuestion: createMockedModifyQuestionUseCase(),
        assignThemeToQuestion: createMockedAssignThemeToQuestionUseCase(),
        removeThemeFromQuestion: createMockedRemoveThemeFromQuestionUseCase(),
        modifyQuestionThemeAssignment: createMockedModifyQuestionThemeAssignmentUseCase(),
      },
      mappers: {
        createAdminQuestionDtoFromEntity: vi.mocked(createAdminQuestionDtoFromEntity),
        createQuestionCreationCommandFromDto: vi.mocked(createQuestionCreationCommandFromDto),
        createQuestionModificationCommandFromDto: vi.mocked(createQuestionModificationCommandFromDto),
        createQuestionThemeAssignmentCreationCommandFromDto: vi.mocked(createQuestionThemeAssignmentCreationCommandFromDto),
        createQuestionThemeAssignmentModificationCommandFromDto: vi.mocked(createQuestionThemeAssignmentModificationCommandFromDto),
        createFindAllOptionsFromQueryDto: vi.mocked(createFindAllOptionsFromQueryDto),
      },
    };

    const testingModule = await Test.createTestingModule({
      controllers: [AdminQuestionController],
      providers: [
        {
          provide: AppConfigService,
          useValue: mocks.services.appConfig,
        },
        {
          provide: FindQuestionsUseCase,
          useValue: mocks.useCases.findQuestions,
        },
        {
          provide: FindQuestionByIdUseCase,
          useValue: mocks.useCases.findQuestionById,
        },
        {
          provide: GetQuestionStatsUseCase,
          useValue: mocks.useCases.getQuestionStats,
        },
        {
          provide: CreateQuestionUseCase,
          useValue: mocks.useCases.createQuestion,
        },
        {
          provide: ArchiveQuestionUseCase,
          useValue: mocks.useCases.archiveQuestion,
        },
        {
          provide: ModifyQuestionUseCase,
          useValue: mocks.useCases.modifyQuestion,
        },
        {
          provide: AssignThemeToQuestionUseCase,
          useValue: mocks.useCases.assignThemeToQuestion,
        },
        {
          provide: RemoveThemeFromQuestionUseCase,
          useValue: mocks.useCases.removeThemeFromQuestion,
        },
        {
          provide: ModifyQuestionThemeAssignmentUseCase,
          useValue: mocks.useCases.modifyQuestionThemeAssignment,
        },
      ],
    }).compile();

    adminQuestionController = testingModule.get<AdminQuestionController>(AdminQuestionController);
  });

  describe(AdminQuestionController.prototype.findQuestions, () => {
    it("should create find all options from query dto when called.", async() => {
      const queryDto = createFakeAdminFindQuestionsQueryDto();
      await adminQuestionController.findQuestions(queryDto);

      expect(mocks.mappers.createFindAllOptionsFromQueryDto).toHaveBeenCalledExactlyOnceWith(queryDto, createQuestionFilterOptionsFromQueryDto);
    });

    it("should list all questions with find all options when called.", async() => {
      const queryDto = createFakeAdminFindQuestionsQueryDto();
      const expectedFindAllOptions: FindAllOptions<QuestionSortableField, QuestionFilterOptions> = { sort: { sortBy: "createdAt", sortOrder: "desc" } };
      mocks.mappers.createFindAllOptionsFromQueryDto.mockReturnValueOnce(expectedFindAllOptions);
      await adminQuestionController.findQuestions(queryDto);

      expect(mocks.useCases.findQuestions.list).toHaveBeenCalledExactlyOnceWith(expectedFindAllOptions);
    });

    it("should map every question to admin dto when called.", async() => {
      const queryDto = createFakeAdminFindQuestionsQueryDto();
      const questions = [
        createFakeQuestion(),
        createFakeQuestion(),
        createFakeQuestion(),
      ];
      mocks.useCases.findQuestions.list.mockResolvedValueOnce(questions);
      await adminQuestionController.findQuestions(queryDto);

      expect(mocks.mappers.createAdminQuestionDtoFromEntity).toHaveBeenCalledTimes(questions.length);
    });

    it("should call the mapper with the correct parameters when called.", async() => {
      const queryDto = createFakeAdminFindQuestionsQueryDto();
      const questions = [
        createFakeQuestion(),
        createFakeQuestion(),
        createFakeQuestion(),
      ];
      mocks.useCases.findQuestions.list.mockResolvedValueOnce(questions);
      await adminQuestionController.findQuestions(queryDto);

      expect(mocks.mappers.createAdminQuestionDtoFromEntity).toHaveBeenCalledWith(questions[0]);
    });

    it("should return the mapped dtos when called.", async() => {
      const queryDto = createFakeAdminFindQuestionsQueryDto();
      const questions = [
        createFakeQuestion(),
        createFakeQuestion(),
      ];
      mocks.useCases.findQuestions.list.mockResolvedValueOnce(questions);
      const expectedDtos = [
        createFakeAdminQuestionDto(),
        createFakeAdminQuestionDto(),
      ];
      mocks.mappers.createAdminQuestionDtoFromEntity.mockReturnValueOnce(expectedDtos[0]).mockReturnValueOnce(expectedDtos[1]);
      const result = await adminQuestionController.findQuestions(queryDto);

      expect(result).toStrictEqual(expectedDtos);
    });
  });

  describe(AdminQuestionController.prototype.getQuestionStats, () => {
    it("should call getQuestionStatsUseCase.getStats when called.", async() => {
      const dto = createFakeQuestionStatsDto();
      mocks.useCases.getQuestionStats.getStats.mockResolvedValueOnce(dto);
      const result = await adminQuestionController.getQuestionStats();

      expect(result).toStrictEqual(dto);
    });

    it("should delegate to the use case exactly once when called.", async() => {
      await adminQuestionController.getQuestionStats();

      expect(mocks.useCases.getQuestionStats.getStats).toHaveBeenCalledExactlyOnceWith();
    });
  });

  describe(AdminQuestionController.prototype.findQuestionById, () => {
    it("should get question by id when called.", async() => {
      const questionId = "123";
      await adminQuestionController.findQuestionById(questionId);

      expect(mocks.useCases.findQuestionById.getById).toHaveBeenCalledExactlyOnceWith(questionId);
    });

    it("should map the question to admin dto when called.", async() => {
      const questionId = "123";
      const question = createFakeQuestion();
      mocks.useCases.findQuestionById.getById.mockResolvedValueOnce(question);
      await adminQuestionController.findQuestionById(questionId);

      expect(mocks.mappers.createAdminQuestionDtoFromEntity).toHaveBeenCalledExactlyOnceWith(question);
    });

    it("should return the mapped dto when called.", async() => {
      const questionId = "123";
      const question = createFakeQuestion();
      mocks.useCases.findQuestionById.getById.mockResolvedValueOnce(question);
      const expectedDto = createFakeAdminQuestionDto();
      mocks.mappers.createAdminQuestionDtoFromEntity.mockReturnValueOnce(expectedDto);

      const result = await adminQuestionController.findQuestionById(questionId);

      expect(result).toStrictEqual(expectedDto);
    });
  });

  describe(AdminQuestionController.prototype.createQuestion, () => {
    it("should map question creation dto to command when called.", async() => {
      const questionCreationDto = createFakeQuestionCreationDto();
      await adminQuestionController.createQuestion(questionCreationDto);

      expect(mocks.mappers.createQuestionCreationCommandFromDto).toHaveBeenCalledExactlyOnceWith(questionCreationDto);
    });

    it("should create question when called.", async() => {
      const questionCreationDto = createFakeQuestionCreationDto();
      const questionCreationCommand = createFakeQuestionCreationCommand();
      mocks.mappers.createQuestionCreationCommandFromDto.mockReturnValueOnce(questionCreationCommand);
      await adminQuestionController.createQuestion(questionCreationDto);

      expect(mocks.useCases.createQuestion.create).toHaveBeenCalledExactlyOnceWith(questionCreationCommand);
    });

    it("should map the created question to dto when created.", async() => {
      const questionCreationDto = createFakeQuestionCreationDto();
      const createdQuestion = createFakeQuestion();
      mocks.useCases.createQuestion.create.mockResolvedValueOnce(createdQuestion);
      await adminQuestionController.createQuestion(questionCreationDto);

      expect(mocks.mappers.createAdminQuestionDtoFromEntity).toHaveBeenCalledExactlyOnceWith(createdQuestion);
    });

    it("should return the mapped dto from the mapper when created.", async() => {
      const questionCreationDto = createFakeQuestionCreationDto();
      const createdQuestion = createFakeQuestion();
      const expectedDto = createFakeAdminQuestionDto();

      mocks.useCases.createQuestion.create.mockResolvedValueOnce(createdQuestion);
      mocks.mappers.createAdminQuestionDtoFromEntity.mockReturnValueOnce(expectedDto);
      const result = await adminQuestionController.createQuestion(questionCreationDto);

      expect(result).toStrictEqual(expectedDto);
    });
  });

  describe(AdminQuestionController.prototype.archiveQuestion, () => {
    it("should archive question when called.", async() => {
      const questionId = "archive-id-1";
      await adminQuestionController.archiveQuestion(questionId);

      expect(mocks.useCases.archiveQuestion.archive).toHaveBeenCalledExactlyOnceWith(questionId);
    });

    it("should map the archived question to admin dto when called.", async() => {
      const questionId = "archive-id-2";
      const archivedQuestion = createFakeQuestion();
      mocks.useCases.archiveQuestion.archive.mockResolvedValueOnce(archivedQuestion);
      await adminQuestionController.archiveQuestion(questionId);

      expect(mocks.mappers.createAdminQuestionDtoFromEntity).toHaveBeenCalledExactlyOnceWith(archivedQuestion);
    });

    it("should return the mapped dto when called.", async() => {
      const questionId = "archive-id-3";
      const archivedQuestion = createFakeQuestion();
      const expectedDto = createFakeAdminQuestionDto();

      mocks.useCases.archiveQuestion.archive.mockResolvedValueOnce(archivedQuestion);
      mocks.mappers.createAdminQuestionDtoFromEntity.mockReturnValueOnce(expectedDto);
      const result = await adminQuestionController.archiveQuestion(questionId);

      expect(result).toStrictEqual(expectedDto);
    });
  });

  describe(AdminQuestionController.prototype.modifyQuestion, () => {
    it("should map question modification dto to command when called.", async() => {
      const questionId = "modify-q-1";
      const dto = createFakeQuestionModificationDto();

      await adminQuestionController.modifyQuestion(questionId, dto);

      expect(mocks.mappers.createQuestionModificationCommandFromDto).toHaveBeenCalledExactlyOnceWith(questionId, dto);
    });

    it("should modify question when called.", async() => {
      const questionId = "modify-q-2";
      const dto = createFakeQuestionModificationDto();
      const command = createFakeQuestionModificationCommand();
      mocks.mappers.createQuestionModificationCommandFromDto.mockReturnValueOnce(command);

      await adminQuestionController.modifyQuestion(questionId, dto);

      expect(mocks.useCases.modifyQuestion.modify).toHaveBeenCalledExactlyOnceWith(command);
    });

    it("should map the modified question to admin dto when called.", async() => {
      const questionId = "modify-q-3";
      const dto = createFakeQuestionModificationDto();
      const modifiedQuestion = createFakeQuestion();
      mocks.useCases.modifyQuestion.modify.mockResolvedValueOnce(modifiedQuestion);

      await adminQuestionController.modifyQuestion(questionId, dto);

      expect(mocks.mappers.createAdminQuestionDtoFromEntity).toHaveBeenCalledExactlyOnceWith(modifiedQuestion);
    });

    it("should return the mapped dto when called.", async() => {
      const questionId = "modify-q-4";
      const dto = createFakeQuestionModificationDto();
      const modifiedQuestion = createFakeQuestion();
      const expectedDto = createFakeAdminQuestionDto();

      mocks.useCases.modifyQuestion.modify.mockResolvedValueOnce(modifiedQuestion);
      mocks.mappers.createAdminQuestionDtoFromEntity.mockReturnValueOnce(expectedDto);

      const result = await adminQuestionController.modifyQuestion(questionId, dto);

      expect(result).toStrictEqual(expectedDto);
    });
  });

  describe(AdminQuestionController.prototype.assignThemeToQuestion, () => {
    it("should map question theme assignment dto to command when called.", async() => {
      const questionId = "q-1";
      const dto = createFakeQuestionThemeAssignmentCreationDto();

      await adminQuestionController.assignThemeToQuestion(questionId, dto);

      expect(mocks.mappers.createQuestionThemeAssignmentCreationCommandFromDto).toHaveBeenCalledExactlyOnceWith(questionId, dto);
    });

    it("should assign theme to question when called.", async() => {
      const questionId = "q-2";
      const dto = createFakeQuestionThemeAssignmentCreationDto();
      const command = createFakeQuestionThemeAssignmentCreationCommand();
      mocks.mappers.createQuestionThemeAssignmentCreationCommandFromDto.mockReturnValueOnce(command);

      await adminQuestionController.assignThemeToQuestion(questionId, dto);

      expect(mocks.useCases.assignThemeToQuestion.assign).toHaveBeenCalledExactlyOnceWith(command);
    });

    it("should map the updated question to admin dto when called.", async() => {
      const questionId = "q-3";
      const dto = createFakeQuestionThemeAssignmentCreationDto();
      const updatedQuestion = createFakeQuestion();
      mocks.useCases.assignThemeToQuestion.assign.mockResolvedValueOnce(updatedQuestion);

      await adminQuestionController.assignThemeToQuestion(questionId, dto);

      expect(mocks.mappers.createAdminQuestionDtoFromEntity).toHaveBeenCalledExactlyOnceWith(updatedQuestion);
    });

    it("should return the mapped dto when called.", async() => {
      const questionId = "q-4";
      const dto = createFakeQuestionThemeAssignmentCreationDto();
      const updatedQuestion = createFakeQuestion();
      const expectedDto = createFakeAdminQuestionDto();

      mocks.useCases.assignThemeToQuestion.assign.mockResolvedValueOnce(updatedQuestion);
      mocks.mappers.createAdminQuestionDtoFromEntity.mockReturnValueOnce(expectedDto);

      const result = await adminQuestionController.assignThemeToQuestion(questionId, dto);

      expect(result).toStrictEqual(expectedDto);
    });
  });

  describe(AdminQuestionController.prototype.removeThemeFromQuestion, () => {
    it("should remove theme from question when called.", async() => {
      const questionId = "q-r-1";
      const themeId = "theme-1";

      await adminQuestionController.removeThemeFromQuestion(questionId, themeId);

      expect(mocks.useCases.removeThemeFromQuestion.remove).toHaveBeenCalledExactlyOnceWith({ questionId, themeId });
    });

    it("should map the updated question to admin dto when called.", async() => {
      const questionId = "q-r-2";
      const themeId = "theme-2";
      const updatedQuestion = createFakeQuestion();
      mocks.useCases.removeThemeFromQuestion.remove.mockResolvedValueOnce(updatedQuestion);

      await adminQuestionController.removeThemeFromQuestion(questionId, themeId);

      expect(mocks.mappers.createAdminQuestionDtoFromEntity).toHaveBeenCalledExactlyOnceWith(updatedQuestion);
    });

    it("should return the mapped dto when called.", async() => {
      const questionId = "q-r-3";
      const themeId = "theme-3";
      const updatedQuestion = createFakeQuestion();
      const expectedDto = createFakeAdminQuestionDto();

      mocks.useCases.removeThemeFromQuestion.remove.mockResolvedValueOnce(updatedQuestion);
      mocks.mappers.createAdminQuestionDtoFromEntity.mockReturnValueOnce(expectedDto);

      const result = await adminQuestionController.removeThemeFromQuestion(questionId, themeId);

      expect(result).toStrictEqual(expectedDto);
    });
  });

  describe(AdminQuestionController.prototype.modifyQuestionThemeAssignment, () => {
    it("should map question theme assignment modification dto to command when called.", async() => {
      const questionId = "q-m-1";
      const themeId = "theme-m-1";
      const dto = createFakeQuestionThemeAssignmentModificationDto();

      await adminQuestionController.modifyQuestionThemeAssignment(questionId, themeId, dto);

      expect(mocks.mappers.createQuestionThemeAssignmentModificationCommandFromDto).toHaveBeenCalledExactlyOnceWith(questionId, themeId, dto);
    });

    it("should modify question theme assignment when called.", async() => {
      const questionId = "q-m-2";
      const themeId = "theme-m-2";
      const dto = createFakeQuestionThemeAssignmentModificationDto();
      const command = createFakeQuestionThemeAssignmentModificationCommand();
      mocks.mappers.createQuestionThemeAssignmentModificationCommandFromDto.mockReturnValueOnce(command);

      await adminQuestionController.modifyQuestionThemeAssignment(questionId, themeId, dto);

      expect(mocks.useCases.modifyQuestionThemeAssignment.modify).toHaveBeenCalledExactlyOnceWith(command);
    });

    it("should map the updated question to admin dto when called.", async() => {
      const questionId = "q-m-3";
      const themeId = "theme-m-3";
      const dto = createFakeQuestionThemeAssignmentModificationDto();
      const updatedQuestion = createFakeQuestion();
      mocks.useCases.modifyQuestionThemeAssignment.modify.mockResolvedValueOnce(updatedQuestion);

      await adminQuestionController.modifyQuestionThemeAssignment(questionId, themeId, dto);

      expect(mocks.mappers.createAdminQuestionDtoFromEntity).toHaveBeenCalledExactlyOnceWith(updatedQuestion);
    });

    it("should return the mapped dto when called.", async() => {
      const questionId = "q-m-4";
      const themeId = "theme-m-4";
      const dto = createFakeQuestionThemeAssignmentModificationDto();
      const updatedQuestion = createFakeQuestion();
      const expectedDto = createFakeAdminQuestionDto();

      mocks.useCases.modifyQuestionThemeAssignment.modify.mockResolvedValueOnce(updatedQuestion);
      mocks.mappers.createAdminQuestionDtoFromEntity.mockReturnValueOnce(expectedDto);

      const result = await adminQuestionController.modifyQuestionThemeAssignment(questionId, themeId, dto);

      expect(result).toStrictEqual(expectedDto);
    });
  });
});

