import { Test } from "@nestjs/testing";

import { ArchiveQuestionUseCase } from "@question/application/use-cases/archive-question/archive-question.use-case";
import { QuestionAlreadyArchivedError } from "@question/domain/errors/question-already-archived/question-already-archived.error";
import { QuestionNotFoundError } from "@question/domain/errors/question-not-found/question-not-found.error";
import { QUESTION_REPOSITORY_TOKEN } from "@question/domain/repositories/question.repository.constants";

import { createMockedQuestionRepository } from "@mocks/contexts/question/infrastructure/persistence/mongoose/question.mongoose.repository.mock";

import { createFakeQuestion } from "@faketories/contexts/question/entity/question.entity.faketory";

describe("Archive Question Use Case", () => {
  let archiveQuestionUseCase: ArchiveQuestionUseCase;
  let mocks: { repositories: { question: ReturnType<typeof createMockedQuestionRepository> } };

  beforeEach(async() => {
    mocks = { repositories: { question: createMockedQuestionRepository() } };

    const testingModule = await Test.createTestingModule({
      providers: [
        ArchiveQuestionUseCase,
        {
          provide: QUESTION_REPOSITORY_TOKEN,
          useValue: mocks.repositories.question,
        },
      ],
    }).compile();

    archiveQuestionUseCase = testingModule.get<ArchiveQuestionUseCase>(ArchiveQuestionUseCase);
  });

  describe(ArchiveQuestionUseCase.prototype.archive, () => {
    beforeEach(() => {
      mocks.repositories.question.findById.mockResolvedValue(createFakeQuestion({ status: "active" }));
    });

    it("should call repository.archive when called.", async() => {
      const id = "question-id-1";

      await archiveQuestionUseCase.archive(id);

      expect(mocks.repositories.question.archive).toHaveBeenCalledExactlyOnceWith(id);
    });

    it("should throw QuestionNotFoundError when repository.archive returns undefined.", async() => {
      const id = "question-id-2";
      mocks.repositories.question.archive.mockResolvedValueOnce(undefined);

      await expect(archiveQuestionUseCase.archive(id)).rejects.toThrow(new QuestionNotFoundError(id));
    });

    it("should return archived question when called.", async() => {
      const id = "question-id-3";
      const archived = createFakeQuestion({ id, status: "archived" });
      mocks.repositories.question.archive.mockResolvedValueOnce(archived);

      const result = await archiveQuestionUseCase.archive(id);

      expect(result).toStrictEqual(archived);
    });
  });

  describe("throwIfQuestionNotArchivable", () => {
    it("should throw QuestionNotFoundError when question is not found.", async() => {
      const id = "non-existent-question-id";
      mocks.repositories.question.findById.mockResolvedValueOnce(undefined);

      await expect(archiveQuestionUseCase["throwIfQuestionNotArchivable"](id)).rejects.toThrow(new QuestionNotFoundError(id));
    });

    it("should throw QuestionAlreadyArchivedError when question is already archived.", async() => {
      const id = "archived-question-id";
      mocks.repositories.question.findById.mockResolvedValueOnce(createFakeQuestion({ id, status: "archived" }));
      const expectedError = new QuestionAlreadyArchivedError(id);

      await expect(archiveQuestionUseCase["throwIfQuestionNotArchivable"](id)).rejects.toThrow(expectedError);
    });

    it("should not throw any error when question is archivable.", async() => {
      const id = "active-question-id";
      mocks.repositories.question.findById.mockResolvedValueOnce(createFakeQuestion({ id, status: "active" }));

      await expect(archiveQuestionUseCase["throwIfQuestionNotArchivable"](id)).resolves.not.toThrow();
    });
  });
});

import { Test } from "@nestjs/testing";

import { FindQuestionByIdUseCase } from "@question/application/use-cases/find-question-by-id/find-question-by-id.use-case";
import { QUESTION_REPOSITORY_TOKEN } from "@question/domain/repositories/question.repository.constants";
import { QuestionPrimaryThemeAssignmentNotRemovableError } from "@question/domain/errors/question-primary-theme-assignment-not-removable/question-primary-theme-assignment-not-removable.error";
import { QuestionThemeAssignmentAbsentError } from "@question/domain/errors/question-theme-assignment-absent/question-theme-assignment-absent.error";
import { QuestionThemeAssignmentRemovalError } from "@question/domain/errors/question-theme-assignment-removal/question-theme-assignment-removal.error";
import { QuestionMinimumThemesError } from "@question/domain/errors/question-minimum-themes/question-minimum-themes.error";
import { RemoveThemeFromQuestionUseCase } from "@question/application/use-cases/question-theme-assignment/remove-theme-from-question/remove-theme-from-question.use-case";

import { createMockedQuestionRepository } from "@mocks/contexts/question/infrastructure/persistence/mongoose/question.mongoose.repository.mock";
import { createMockedFindQuestionByIdUseCase } from "@mocks/contexts/question/application/use-cases/find-question-by-id.use-case.mock";

import { createFakeQuestionThemeAssignmentRemovalCommand } from "@faketories/contexts/question/commands/question-theme-assignment/commands/question-theme-assignment.commands.faketory";
import { createFakeQuestionTheme } from "@faketories/contexts/question-theme/entity/question-theme.entity.faketory";
import { createFakeQuestion, createFakeQuestionThemeAssignment } from "@faketories/contexts/question/entity/question.entity.faketory";

describe("Remove Theme From Question Use Case", () => {
  let useCase: RemoveThemeFromQuestionUseCase;
  let mocks: {
    repositories: {
      question: ReturnType<typeof createMockedQuestionRepository>;
    };
    useCases: {
      findQuestionById: ReturnType<typeof createMockedFindQuestionByIdUseCase>;
    };
  };

  beforeEach(async() => {
    mocks = {
      repositories: {
        question: createMockedQuestionRepository(),
      },
      useCases: {
        findQuestionById: createMockedFindQuestionByIdUseCase(),
      },
    };

    const module = await Test.createTestingModule({
      providers: [
        RemoveThemeFromQuestionUseCase,
        {
          provide: QUESTION_REPOSITORY_TOKEN,
          useValue: mocks.repositories.question,
        },
        {
          provide: FindQuestionByIdUseCase,
          useValue: mocks.useCases.findQuestionById,
        },
      ],
    }).compile();

    useCase = module.get(RemoveThemeFromQuestionUseCase);
  });

  describe(RemoveThemeFromQuestionUseCase.prototype.remove, () => {
    it("should throw QuestionThemeAssignmentRemovalError when repository returns undefined.", async() => {
      const command = createFakeQuestionThemeAssignmentRemovalCommand({
        questionId: "q3",
        themeId: "theme-1",
      });
      const question = createFakeQuestion({
        id: "q3",
        themes: [
          createFakeQuestionThemeAssignment({
            theme: createFakeQuestionTheme({ id: "theme-1" }),
            isPrimary: false,
          }),
          createFakeQuestionThemeAssignment({
            theme: createFakeQuestionTheme({ id: "theme-2" }),
            isPrimary: false,
          }),
        ],
      });
      vi.mocked(mocks.useCases.findQuestionById.getById).mockResolvedValueOnce(question);
      vi.mocked(mocks.repositories.question.removeTheme).mockResolvedValueOnce(undefined);
      const expectedError = new QuestionThemeAssignmentRemovalError(command.themeId, command.questionId);

      await expect(useCase.remove(command)).rejects.toThrow(expectedError);
    });

    it("should call repository remove method when called.", async() => {
      const command = createFakeQuestionThemeAssignmentRemovalCommand({
        questionId: "q3",
        themeId: "theme-1",
      });
      const question = createFakeQuestion({
        id: "q3",
        themes: [
          createFakeQuestionThemeAssignment({
            theme: createFakeQuestionTheme({ id: "theme-1" }),
            isPrimary: false,
          }),
          createFakeQuestionThemeAssignment({
            theme: createFakeQuestionTheme({ id: "theme-2" }),
            isPrimary: false,
          }),
        ],
      });
      vi.mocked(mocks.useCases.findQuestionById.getById).mockResolvedValueOnce(question);
      const updated = createFakeQuestion();
      vi.mocked(mocks.repositories.question.removeTheme).mockResolvedValueOnce(updated);

      await useCase.remove(command);

      expect(mocks.repositories.question.removeTheme).toHaveBeenCalledExactlyOnceWith(command.questionId, command.themeId);
    });

    it("should return updated question when repository succeeds.", async() => {
      const command = createFakeQuestionThemeAssignmentRemovalCommand({
        questionId: "q3",
        themeId: "theme-1",
      });
      const question = createFakeQuestion({
        id: "q3",
        themes: [
          createFakeQuestionThemeAssignment({
            theme: createFakeQuestionTheme({ id: "theme-1" }),
            isPrimary: false,
          }),
          createFakeQuestionThemeAssignment({
            theme: createFakeQuestionTheme({ id: "theme-2" }),
            isPrimary: false,
          }),
        ],
      });
      vi.mocked(mocks.useCases.findQuestionById.getById).mockResolvedValueOnce(question);
      const updated = createFakeQuestion();
      vi.mocked(mocks.repositories.question.removeTheme).mockResolvedValueOnce(updated);

      const result = await useCase.remove(command);

      expect(result).toStrictEqual(updated);
    });
  });

  describe("throwIfThemeNotRemovableFromQuestion", () => {
    it("should throw QuestionMinimumThemesError when question has minimum themes.", async() => {
      const command = createFakeQuestionThemeAssignmentRemovalCommand({
        questionId: "q1",
        themeId: "existing-theme",
      });
      const question = createFakeQuestion({
        id: "q1",
        themes: [
          createFakeQuestionThemeAssignment({
            theme: createFakeQuestionTheme({ id: "existing-theme" }),
            isPrimary: false,
          }),
        ],
      });
      vi.mocked(mocks.useCases.findQuestionById.getById).mockResolvedValueOnce(question);
      const expectedError = new QuestionMinimumThemesError(command.questionId);

      await expect(useCase["throwIfThemeNotRemovableFromQuestion"](command.questionId, command.themeId)).rejects.toThrow(expectedError);
    });

    it("should throw QuestionThemeAssignmentAbsentError when question has no themes.", async() => {
      const command = createFakeQuestionThemeAssignmentRemovalCommand({
        questionId: "q0",
        themeId: "missing-theme",
      });
      const question = createFakeQuestion({
        id: "q0",
        themes: [],
      });
      vi.mocked(mocks.useCases.findQuestionById.getById).mockResolvedValueOnce(question);
      const expectedError = new QuestionThemeAssignmentAbsentError(command.themeId, command.questionId);

      await expect(useCase["throwIfThemeNotRemovableFromQuestion"](command.questionId, command.themeId)).rejects.toThrow(expectedError);
    });

    it("should throw QuestionThemeAssignmentAbsentError when theme not assigned.", async() => {
      const command = createFakeQuestionThemeAssignmentRemovalCommand({
        questionId: "q2",
        themeId: "missing-theme",
      });
      const question = createFakeQuestion({
        id: "q2",
        themes: [
          createFakeQuestionThemeAssignment({
            theme: createFakeQuestionTheme({ id: "existing-theme" }),
          }),
          createFakeQuestionThemeAssignment({
            theme: createFakeQuestionTheme({ id: "existing-theme-2" }),
          }),
        ],
      });
      vi.mocked(mocks.useCases.findQuestionById.getById).mockResolvedValueOnce(question);
      const expectedError = new QuestionThemeAssignmentAbsentError(command.themeId, command.questionId);

      await expect(useCase["throwIfThemeNotRemovableFromQuestion"](command.questionId, command.themeId)).rejects.toThrow(expectedError);
    });

    it("should throw QuestionPrimaryThemeAssignmentNotRemovableError when theme is primary.", async() => {
      const command = createFakeQuestionThemeAssignmentRemovalCommand({
        questionId: "q-primary",
        themeId: "primary-theme",
      });
      const question = createFakeQuestion({
        id: "q-primary",
        themes: [
          createFakeQuestionThemeAssignment({
            theme: createFakeQuestionTheme({ id: "primary-theme" }),
            isPrimary: true,
          }),
          createFakeQuestionThemeAssignment({
            theme: createFakeQuestionTheme({ id: "other-theme" }),
            isPrimary: false,
          }),
        ],
      });
      vi.mocked(mocks.useCases.findQuestionById.getById).mockResolvedValueOnce(question);
      const expectedError = new QuestionPrimaryThemeAssignmentNotRemovableError(command.themeId, command.questionId);

      await expect(useCase["throwIfThemeNotRemovableFromQuestion"](command.questionId, command.themeId)).rejects.toThrow(expectedError);
    });
  });
});

import { Test } from "@nestjs/testing";

import { FindQuestionThemeByIdUseCase } from "@question-theme/application/use-cases/find-question-theme-by-id/find-question-theme-by-id.use-case";
import { ReferencedQuestionThemeArchivedError } from "@question-theme/domain/errors/referenced-question-theme-archived/referenced-question-theme-archived.error";
