        isHint: questionThemeAssignment.isHint,
      });
      const result = createQuestionThemeAssignmentDtoFromEntity(questionThemeAssignment, localizationOptions);

      expect(result).toStrictEqual(expectedQuestionThemeAssignmentDto);
