      const dto = createFakeQuestionThemeAssignmentCreationDto();
      const command = createQuestionThemeAssignmentCreationCommandFromDto("q-1", dto);
      const expectedCommand = createFakeQuestionThemeAssignmentCreationCommand({
        questionId: "q-1",
